#include <bits/stdc++.h>
using namespace std;
int main(){
    char p[260];
    int a=0,b=0,c=0,wb;
    cin>>p;
    for(int i=0;i<strlen(p);i++){
        if(p[i+1]!=';'){
            if(p[i]=='a')wb=1;
            else if(p[i]=='b')wb=2;
            else if(p[i]=='c')wb=3;
        }else if(p[i+1]==';'){
            if(p[i]>='0' && p[i]<='9'){
                if(wb==1)a=p[i]-'0';
                else if(wb==2)b=p[i]-'0';
                else if(wb==3)c=p[i]-'0';
            }else{
                if(p[i]=='a'){
                    if(wb==1)a=a;
                    else if(wb==2)b=a;
                    else if(wb==3)c=a;
                }else if(p[i]=='b'){
                    if(wb==1)a=b;
                    else if(wb==2)b=b;
                    else if(wb==3)c=b;
                }else if(p[i]=='c'){
                    if(wb==1)a=c;
                    else if(wb==2)b=c;
                    else if(wb==3)c=c;
                }
            }
        }
    }
    cout<<a<<' '<<b<<' '<<c;
    return 0;
}
